#include <bits/stdc++.h>
#define da(i) d[i].a
#define db(i) d[i].b
#define dc(i) d[i].c
using namespace std;
const int maxn=1e5+5;
int n,ans;
struct C{
    int a,b,c;
}d[maxn];
vector<int>ve;
int l;
int main(void){
    scanf("%d", &n);
    for(int i=1;i<=n;++i){
        scanf("%d%d%d",&da(i),&db(i),&dc(i));
        ans+=db(i);
        if(!da(i)){
            ve.push_back(i);
            continue;
        }
        while(l<ve.size()){
            if(dc(i)-dc(ve[l])<=45)break;
            l++;
        }
        for(int j=l;j<ve.size();++j){
            if(da(ve[j]))continue;
            if(db(ve[j])<db(i))continue;
            da(ve[j])=1;
            ans-=db(i);
            break;
        }
    }
    printf("%d",ans);
    return false;
}
